mapper.sql:
q.is_deleted=0


        AND (q.title LIKE CONCAT('%', #{q.keyword}, '%')
             OR q.stem LIKE CONCAT('%', #{q.keyword}, '%'))


        AND q.chapter = #{q.chapter}


        AND q.difficulty = #{q.difficulty}


        AND q.question_type = #{q.questionType}


        AND q.status = #{q.status}


        AND q.created_by = #{q.createdBy}


        AND EXISTS (
            SELECT 1 FROM qb_question_tag qt
            WHERE qt.question_id = q.id AND qt.tag_id = #{q.tagId}
        )


        AND EXISTS (
            SELECT 1 FROM qb_question_tag qt
            WHERE qt.question_id = q.id
              AND qt.tag_id IN

                  #{tid}

        )
